print_color_system_info(){
    echo -e "\e[${BG_COLOR_NAME_ANSI};${COLOR_NAME_ANSI}mHOSTNAME\e[0m = \e[${BG_COLOR_VAL_ANSI};${COLOR_VAL_ANSI}m$HOSTNAME\e[0m"
    echo -e "\e[${BG_COLOR_NAME_ANSI};${COLOR_NAME_ANSI}mTIMEZONE\e[0m = \e[${BG_COLOR_VAL_ANSI};${COLOR_VAL_ANSI}m$TIMEZONE\e[0m"
