    echo -e "\e[${BG_COLOR_NAME_ANSI};${COLOR_NAME_ANSI}mDATE\e[0m = \e[${BG_COLOR_VAL_ANSI};${COLOR_VAL_ANSI}m$DATE\e[0m"
